interfaces.interface:
                ${enet\-name}
<#if eth\-port\-hw\-option == "veip" >
                bbf-xponift:onu-v-vrefpoint
                true
                VEIPPORT${eth\-port\-hw\-number}

<#if ani\-name?has_content>
                  ${ani\-name}
</#if>

<#else>
                ianaift:ethernetCsmacd
                PORT_${eth\-port\-hw\-option}_${eth\-port\-hw\-number}


                    enabled
<#if pluggable\-optical\-electrical\-SFP?has_content && pluggable\-optical\-electrical\-SFP== true && fec?has_content >
                    ${fec}
</#if>


</#if>
<#if disable\-upon\-ponlos?has_content>
                ${disable\-upon\-ponlos}
</#if>
